// admin-survey.js - Admin survey management functionalityconsole.log('admin-survey.js loaded - version 2');class AdminSurveyPage { constructor() { console.log('AdminSurveyPage constructor called'); this.surveyId = null; this.survey = null; this.questions = []; this.currentUser = null; this.init(); } async init() { // Check if user is logged in and is admin if (!window.app.isLoggedIn()) { window.location.href = '/login'; return; } this.currentUser = window.app.currentUser; if (this.currentUser.role !== 'admin') { window.location.href = '/'; return; } // Get survey ID from URL const urlParts = window.location.pathname.split('/'); this.surveyId = parseInt(urlParts[urlParts.length - 1]); if (!this.surveyId) { window.location.href = '/admin/surveys'; return; } // Setup event listeners this.setupEventListeners(); // Load survey data await this.loadSurvey(); await this.loadQuestions(); } setupEventListeners() { // Survey form const surveyForm = document.getElementById('edit-survey-form'); if (surveyForm) { surveyForm.addEventListener('submit', (e) => { e.preventDefault(); this.updateSurvey(); }); } // Add question button const addQuestionBtn = document.getElementById('add-question-btn'); if (addQuestionBtn) { addQuestionBtn.addEventListener('click', () => { this.showAddQuestionForm(); }); } // Add question form const addQuestionForm = document.getElementById('add-question-form'); if (addQuestionForm) { addQuestionForm.addEventListener('submit', (e) => { e.preventDefault(); this.addQuestion(); }); // Question type change const questionType = document.getElementById('question-type'); if (questionType) { questionType.addEventListener('change', (e) => { this.toggleOptionsGroup(e.target.value); }); } } // Edit question form const editQuestionForm = document.getElementById('edit-question-form'); if (editQuestionForm) { editQuestionForm.addEventListener('submit', (e) => { e.preventDefault(); this.updateQuestion(); }); // Question type change const editQuestionType = document.getElementById('edit-question-type'); if (editQuestionType) { editQuestionType.addEventListener('change', (e) => { this.toggleEditOptionsGroup(e.target.value); }); } } // Logout button const logoutBtn = document.getElementById('logout-btn'); if (logoutBtn) { logoutBtn.addEventListener('click', () => window.app.logout()); } } async loadSurvey() { try { const loading = document.getElementById('loading'); const errorMessage = document.getElementById('error-message'); const surveyContainer = document.getElementById('survey-container'); loading.style.display = 'block'; errorMessage.style.display = 'none'; surveyContainer.style.display = 'none'; this.survey = await window.app.apiRequest(`/api/surveys/${this.surveyId}`); loading.style.display = 'none'; surveyContainer.style.display = 'block'; this.renderSurvey(); } catch (error) { console.error('Error loading survey:', error); const loading = document.getElementById('loading'); const errorMessage = document.getElementById('error-message'); loading.style.display = 'none'; errorMessage.style.display = 'block'; } } renderSurvey() { document.getElementById('title').value = this.survey.title; document.getElementById('description').value = this.survey.description; document.getElementById('status').value = this.survey.status; // Disable add question button for non-draft surveys const addQuestionBtn = document.getElementById('add-question-btn'); if (addQuestionBtn) { if (this.survey.status !== 'draft') { addQuestionBtn.disabled = true; addQuestionBtn.textContent = '📝 Добавлять вопросы можно только в черновики'; addQuestionBtn.title = 'Чтобы добавить вопросы, измените статус опроса на "Черновик"'; } else { addQuestionBtn.disabled = false; addQuestionBtn.textContent = '➕ Добавить вопрос'; addQuestionBtn.title = ''; } } } async loadQuestions() { console.log('loadQuestions called for survey:', this.surveyId); try { console.log('Loading questions for survey:', this.surveyId); // Use getSurvey endpoint which includes questions const surveyWithQuestions = await window.app.apiRequest(`/api/surveys/${this.surveyId}`); console.log('Survey with questions loaded:', surveyWithQuestions); this.questions = surveyWithQuestions.questions || []; console.log('Questions extracted:', this.questions); this.renderQuestions(); } catch (error) { console.error('Error loading questions:', error); this.questions = []; this.renderQuestions(); } } renderQuestions() { const container = document.getElementById('questions-container'); if (!container) return; container.innerHTML = this.questions.map((question, index) => ` <div class="question-card" data-question-id="${question.id}"> <div class="question-header"> <h4>Вопрос ${index + 1}</h4> <div class="question-actions"> ${this.survey.status === 'draft' ? ` <button class="btn btn-secondary btn-sm" onclick="adminSurveyPage.editQuestion(${question.id})"> ✏️ Редактировать </button> <button class="btn btn-danger btn-sm" onclick="adminSurveyPage.deleteQuestion(${question.id})"> 🗑️ Удалить </button> ` : ''} </div> </div> <div class="question-content"> <p class="question-text">${question.text}</p> <div class="question-meta"> <span class="question-type">${this.getQuestionTypeText(question.type)}</span> ${question.is_required ? '<span class="required-badge">Обязательный</span>' : ''} </div> ${question.options ? ` <div class="question-options"> ${question.options.map((option, i) => ` <div class="option-item"> <span class="option-letter">${String.fromCharCode(65 + i)}.</span> <span class="option-text">${option}</span> </div> `).join('')} </div> ` : ''} </div> </div> `).join(''); } getQuestionTypeText(type) { const types = { 'text': '📝 Текстовый ответ', 'single_choice': '📢 Выбор варианта' }; return types[type] || type; } async updateSurvey() { try { const formData = new FormData(document.getElementById('edit-survey-form')); const data = { title: formData.get('title'), description: formData.get('description'), status: formData.get('status') }; await window.app.apiRequest(`/api/surveys/${this.surveyId}`, { method: 'PUT', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(data) }); // Show success message this.showMessage('Опрос успешно обновлен!', 'success'); // Reload survey data await this.loadSurvey(); } catch (error) { console.error('Error updating survey:', error); this.showMessage('Ошибка при обновлении опроса', 'error'); } } showAddQuestionForm() { const modal = document.getElementById('add-question-modal'); modal.style.display = 'flex'; this.resetAddQuestionForm(); // Close modal when clicking outside modal.onclick = (e) => { if (e.target === modal) { this.hideAddQuestionModal(); } }; } hideAddQuestionModal() { const modal = document.getElementById('add-question-modal'); modal.style.display = 'none'; modal.onclick = null; } resetAddQuestionForm() { const form = document.getElementById('add-question-form'); if (form) form.reset(); // Clear options const optionsContainer = document.getElementById('options-container'); if (optionsContainer) optionsContainer.innerHTML = ''; // Hide options group this.toggleOptionsGroup('text'); } toggleOptionsGroup(type) { const optionsGroup = document.getElementById('options-group'); if (optionsGroup) { optionsGroup.style.display = type === 'single_choice' ? 'block' : 'none'; } } addOption() { const container = document.getElementById('options-container'); if (!container) return; const optionCount = container.children.length; const optionDiv = document.createElement('div'); optionDiv.className = 'option-input'; optionDiv.innerHTML = ` <input type="text" name="option_${optionCount}" placeholder="Вариант ответа ${optionCount + 1}" required> <button type="button" class="btn btn-danger btn-sm" onclick="this.parentElement.remove()">🗑️</button> `; container.appendChild(optionDiv); } async addQuestion() { try { const formData = new FormData(document.getElementById('add-question-form')); const data = { text: formData.get('text'), type: formData.get('type'), is_required: formData.has('is_required') }; console.log('Adding question:', data); console.log('Survey ID:', this.surveyId); console.log('Current user:', this.currentUser); // Add options for single_choice questions if (data.type === 'single_choice') { data.options = []; const options = document.querySelectorAll('#options-container input[type="text"]'); options.forEach(input => { if (input.value.trim()) { data.options.push(input.value.trim()); } }); if (data.options.length < 2) { this.showMessage('Для вопроса с выбором варианта нужно минимум 2 варианта ответа', 'error'); return; } } const response = await window.app.apiRequest(`/api/surveys/${this.surveyId}/questions`, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(data) }); console.log('Question added response:', response); this.showMessage('Вопрос успешно добавлен!', 'success'); this.hideAddQuestionModal(); await this.loadQuestions(); } catch (error) { console.error('Error adding question:', error); this.showMessage('Ошибка при добавлении вопроса: ' + error.message, 'error'); } } editQuestion(questionId) { const question = this.questions.find(q => q.id === questionId); if (!question) return; const modal = document.getElementById('edit-question-modal'); modal.style.display = 'flex'; // Fill form with question data document.getElementById('edit-question-id').value = question.id; document.getElementById('edit-question-text').value = question.text; document.getElementById('edit-question-type').value = question.type; document.getElementById('edit-question-required').checked = question.is_required; // Load options for single_choice questions if (question.type === 'single_choice' && question.options) { const container = document.getElementById('edit-options-container'); container.innerHTML = ''; question.options.forEach((option, index) => { const optionDiv = document.createElement('div'); optionDiv.className = 'option-input'; optionDiv.innerHTML = ` <input type="text" name="edit_option_${index}" value="${option}" placeholder="Вариант ответа ${index + 1}" required> <button type="button" class="btn btn-danger btn-sm" onclick="this.parentElement.remove()">🗑️</button> `; container.appendChild(optionDiv); }); } this.toggleEditOptionsGroup(question.type); // Close modal when clicking outside modal.onclick = (e) => { if (e.target === modal) { this.hideEditQuestionModal(); } }; } hideEditQuestionModal() { const modal = document.getElementById('edit-question-modal'); modal.style.display = 'none'; modal.onclick = null; } // Custom modal methods showConfirmModal(title, message, onConfirm) { const modal = document.getElementById('confirm-modal'); const titleEl = document.getElementById('confirm-title'); const messageEl = document.getElementById('confirm-message'); const confirmBtn = document.getElementById('confirm-btn'); titleEl.textContent = title; messageEl.textContent = message; // Remove old event listener const newConfirmBtn = confirmBtn.cloneNode(true); confirmBtn.parentNode.replaceChild(newConfirmBtn, confirmBtn); // Add new event listener newConfirmBtn.addEventListener('click', () => { this.hideConfirmModal(); if (onConfirm) onConfirm(); }); modal.style.display = 'flex'; // Close modal when clicking outside modal.onclick = (e) => { if (e.target === modal) { this.hideConfirmModal(); } }; } hideConfirmModal() { const modal = document.getElementById('confirm-modal'); modal.style.display = 'none'; modal.onclick = null; } showAlertModal(title, message) { const modal = document.getElementById('alert-modal'); const titleEl = document.getElementById('alert-title'); const messageEl = document.getElementById('alert-message'); titleEl.textContent = title; messageEl.textContent = message; modal.style.display = 'flex'; // Close modal when clicking outside modal.onclick = (e) => { if (e.target === modal) { this.hideAlertModal(); } }; } hideAlertModal() { const modal = document.getElementById('alert-modal'); modal.style.display = 'none'; modal.onclick = null; } toggleEditOptionsGroup(type) { const optionsGroup = document.getElementById('edit-options-group'); if (optionsGroup) { optionsGroup.style.display = type === 'single_choice' ? 'block' : 'none'; } } addEditOption() { const container = document.getElementById('edit-options-container'); if (!container) return; const optionCount = container.children.length; const optionDiv = document.createElement('div'); optionDiv.className = 'option-input'; optionDiv.innerHTML = ` <input type="text" name="edit_option_${optionCount}" placeholder="Вариант ответа ${optionCount + 1}" required> <button type="button" class="btn btn-danger btn-sm" onclick="this.parentElement.remove()">🗑️</button> `; container.appendChild(optionDiv); } async updateQuestion() { try { const formData = new FormData(document.getElementById('edit-question-form')); const questionId = parseInt(formData.get('question-id')); const data = { text: formData.get('text'), type: formData.get('type'), is_required: formData.has('is_required') }; // Add options for single_choice questions if (data.type === 'single_choice') { data.options = []; const options = document.querySelectorAll('#edit-options-container input[type="text"]'); options.forEach(input => { if (input.value.trim()) { data.options.push(input.value.trim()); } }); if (data.options.length < 2) { this.showMessage('Для вопроса с выбором варианта нужно минимум 2 варианта ответа', 'error'); return; } } await window.app.apiRequest(`/api/surveys/${this.surveyId}/questions/${questionId}`, { method: 'PUT', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(data) }); this.showMessage('Вопрос успешно обновлен!', 'success'); this.hideEditQuestionModal(); await this.loadQuestions(); } catch (error) { console.error('Error updating question:', error); this.showMessage('Ошибка при обновлении вопроса', 'error'); } } async deleteQuestion(questionId) { this.showConfirmModal( '⚠️ Подтверждение удаления', 'Вы уверены, что хотите удалить этот вопрос? Это действие нельзя отменить.', async () => { try { await window.app.apiRequest(`/api/surveys/${this.surveyId}/questions/${questionId}`, { method: 'DELETE' }); this.showMessage('Вопрос успешно удален!', 'success'); await this.loadQuestions(); } catch (error) { console.error('Error deleting question:', error); this.showMessage('Ошибка при удалении вопроса', 'error'); } } ); } showMessage(text, type = 'info') { // Create a simple message element const messageDiv = document.createElement('div'); messageDiv.className = `message message-${type}`; messageDiv.textContent = text; messageDiv.style.cssText = ` position: fixed; top: 20px; right: 20px; padding: 15px 20px; border-radius: 8px; background: ${type === 'success' ? '#10b981' : type === 'error' ? '#ef4444' : '#3b82f6'}; color: white; z-index: 1000; box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1); `; document.body.appendChild(messageDiv); setTimeout(() => { messageDiv.remove(); }, 3000); }}// Initialize page when DOM is loadeddocument.addEventListener('DOMContentLoaded', () => { window.adminSurveyPage = new AdminSurveyPage();});